    if (typeof Trumpet !== 'undefined') { Trumpet.sms(phone, body); }
    else { window.open('sms:' + encodeURIComponent(phone.replace(/[^\d+]/g, '')) + (body ? '?body=' + encodeURIComponent(body) : '')); }
