      + '<button type="button" onclick="Modules._trumpetSms(\'' + _e(phone) + '\')" style="background:none;border:none;cursor:pointer;font-size:0.85rem;padding:0;" title="Text">\uD83D\uDCAC</button>'
      + '</span>';
