              + '<button onclick="Modules._sermonSeriesDelete(\'' + sid + '\')" style="font-size:0.76rem;padding:7px 10px;border:1px solid var(--danger);border-radius:6px;background:none;color:var(--danger);cursor:pointer;font-family:inherit;">Delete</button>'
