          + '<input id="disc-path-search" type="text" placeholder="🔍 Filter paths…" oninput="Modules._discFilterPaths()" style="flex:1;min-width:120px;max-width:260px;padding:7px 11px;border:1px solid var(--line);border-radius:7px;background:var(--bg-raised);color:var(--ink);font-size:0.82rem;font-family:inherit;">'
