          + '</select>'
          + '<select id="disc-path-level" onchange="Modules._discFilterPaths()" style="padding:7px 10px;border:1px solid var(--line);border-radius:7px;background:var(--bg-raised);color:var(--ink);font-size:0.78rem;font-family:inherit;">'
