          + '<select id="disc-ment-status" onchange="Modules._discFilterMentoring()" style="padding:7px 10px;border:1px solid var(--line);border-radius:7px;background:var(--bg-raised);color:var(--ink);font-size:0.78rem;font-family:inherit;">'
          + '<option value="">All Statuses</option><option value="active">Active</option><option value="completed">Completed</option><option value="paused">Paused</option>'
          + '</select>'
          + '<input id="disc-ment-search" type="text" placeholder="🔍 Search mentor or mentee…" oninput="Modules._discFilterMentoring()" style="flex:1;min-width:120px;max-width:280px;padding:7px 11px;border:1px solid var(--line);border-radius:7px;background:var(--bg-raised);color:var(--ink);font-size:0.82rem;font-family:inherit;">'
          + '</div>';
        html += '<div id="disc-ment-table">'
