        html += '<div style="background:var(--bg-raised);border:1px solid rgba(232,168,56,0.3);border-left:3px solid var(--gold,#d4a843);border-radius:10px;padding:14px 18px;margin-bottom:18px;text-align:center;">'
          + '<div style="font-size:0.78rem;font-style:italic;color:var(--ink);line-height:1.55;">"The harvest is plentiful, but the workers are few. Ask the Lord of the harvest, therefore, to send out workers into his harvest field." — Luke 10:2</div>'
          + '</div>';

        // Filter bar
        html += '<div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap;margin-bottom:14px;">'
          + '<input id="missions-search" type="text" placeholder="🔍 Search countries…" oninput="Modules._missionsFilter()" style="flex:1;min-width:160px;max-width:300px;padding:7px 11px;border:1px solid var(--line);border-radius:7px;background:var(--bg-raised);color:var(--ink);font-size:0.82rem;font-family:inherit;">'
          + '<select id="missions-pers-filter" onchange="Modules._missionsFilter()" style="padding:7px 10px;border:1px solid var(--line);border-radius:7px;background:var(--bg-raised);color:var(--ink);font-size:0.78rem;font-family:inherit;">'
          + '<option value="">All Persecution Levels</option>'
          + '<option value="extreme">Extreme</option>'
          + '<option value="very high">Very High</option>'
          + '<option value="high">High</option>'
          + '<option value="moderate">Moderate</option>'
          + '</select>'
          + '<select id="missions-access-filter" onchange="Modules._missionsFilter()" style="padding:7px 10px;border:1px solid var(--line);border-radius:7px;background:var(--bg-raised);color:var(--ink);font-size:0.78rem;font-family:inherit;">'
          + '<option value="">All Gospel Access</option>'
          + '<option value="unreached">Unreached</option>'
          + '<option value="limited">Limited</option>'
          + '<option value="restricted">Restricted</option>'
          + '<option value="open">Open</option>'
          + '</select>'
          + '</div>';

        // Country grid
        if (rows.length === 0) {
          html += '<div style="text-align:center;padding:48px 16px;">'
            + '<div style="font-size:2.5rem;margin-bottom:12px;">🌍</div>'
            + '<div style="font-weight:700;margin-bottom:6px;">No countries tracked yet</div>'
            + '<div style="color:var(--ink-muted);font-size:0.85rem;margin-bottom:16px;">Add your first country to begin building your missions intelligence network.</div>'
            + '<button onclick="Modules.newMissionsCountry()" style="background:var(--accent);color:var(--ink-inverse);border:none;border-radius:7px;padding:9px 20px;font-weight:600;cursor:pointer;">+ Add Country</button>'
            + '</div>';
        } else {
          html += '<div id="missions-grid" style="display:grid;grid-template-columns:repeat(auto-fill,minmax(200px,1fr));gap:12px;">';
          rows.forEach(r => { html += _countryCard(r); });
          html += '</div>';
        }

        // Resource links bar
        html += '<div style="margin-top:24px;padding:14px 16px;background:var(--bg-raised);border:1px solid var(--line);border-radius:10px;">'
