  // 27. AUDIT  (pastor+)
  // ═══════════════════════════════════════════════════════════════════════
  _def('audit', async el => {
    if (typeof TheVine !== 'undefined' && !TheVine.hasRole('pastor') && !(typeof Nehemiah !== 'undefined' && (Nehemiah.hasGroup('Master') || Nehemiah.hasGroup('Seed Admin') || Nehemiah.hasGroup('Lead Pastor')))) {
      el.innerHTML = '<div style="text-align:center;padding:80px 20px;">'
        + '<div style="font-size:3rem;margin-bottom:12px;">&#128274;</div>'
        + '<p style="color:var(--ink-muted);">Pastor access required.</p></div>';
      return;
    }
    _shell(el, 'Audit Log', 'System activity, changes & security events.', '');

    // ── Background async — fetch data and fill table when ready ──────────
    (async function _loadAudit() {
    try {
      const res  = await TheVine.flock.call('audit.list', { limit: 500 });
      const rows = _rows(res);
      // Client-side pagination
      var pg = _pgState('audit');
      var start = pg.page * pg.size;
      var pageSlice = rows.slice(start, start + pg.size);
      pg.count   = pageSlice.length;
      pg.hasMore = start + pg.size < rows.length;
      pg.total   = rows.length;
      _body(el, _table(
        ['Timestamp', 'User', 'Action', 'Target', 'Details'],
        pageSlice.map(r => [
          _e(r.createdAt || r.timestamp || ''),
          _e(r.actorEmail || r.user || ''),
          _e(r.action || ''),
          _e(r.entityType ? r.entityType + (r.entityId ? ' / ' + r.entityId : '') : ''),
          _e((r.details || r.notes || '').substring(0, 80)),
        ])
      ) + _pagerBar('audit'));
    } catch (e) { _body(el, _errHtml(e.message)); }
    })();
  });


  // ═══════════════════════════════════════════════════════════════════════
  // 28. ACCESS CONTROL  (admin — role assignments per user)
  // ═══════════════════════════════════════════════════════════════════════
  _def('access', async el => {
    const ROLES = ['readonly', 'volunteer', 'care', 'deacon', 'leader', 'treasurer', 'pastor', 'admin'];
    const ROLE_LABELS = {
      readonly: 'Read Only', volunteer: 'Volunteer', care: 'Care',
      deacon: 'Deacon', leader: 'Leader', treasurer: 'Treasurer',
      pastor: 'Pastor', admin: 'Admin'
    };
    const ROLE_COLOR = {
      readonly: 'info', volunteer: 'info', care: 'info',
      deacon: 'warn', leader: 'warn', treasurer: 'warn',
      pastor: 'success', admin: 'danger'
    };

    function _rSel(email, current) {
      var ee = _e(email);
      var h = '<select onchange="Modules._accessSetRole(\'' + ee + '\', this.value)"'
        + ' style="background:rgba(255,255,255,0.07);border:1px solid var(--line);border-radius:5px;'
        + 'padding:4px 8px;color:var(--ink);font-size:0.82rem;font-family:inherit;">';
      ROLES.forEach(function(r) {
        h += '<option value="' + r + '"' + (r === current ? ' selected' : '') + '>'
           + (ROLE_LABELS[r] || r) + '</option>';
      });
      return h + '</select>';
    }

    async function _render() {
      _shell(el, 'Access Control', 'Manage user roles and system access.', '');
      try {
        var res  = await _fetch('access-list', () => _isFirebaseComms() ? UpperRoom.listAccess() : TheVine.flock.access.list(), _TTL.crm);
        var rows = _rows(res);

        var h = '';

        // ── Add / Update User form ─────────────────────────────────────
        h += '<div style="background:var(--bg-raised);border:1px solid var(--line);border-radius:var(--radius-md,10px);'
           + 'padding:18px 20px;margin-bottom:22px;">';
        h += '<h4 style="margin:0 0 14px;font-size:0.88rem;font-weight:700;color:var(--accent);">Add / Update User</h4>';
        h += '<div style="display:flex;flex-wrap:wrap;gap:10px;align-items:flex-end;">';
        h += '<div style="flex:2;min-width:180px;">'
           + '<label style="display:block;font-size:0.7rem;color:var(--ink-muted);margin-bottom:4px;">Email</label>'
           + '<input id="ac-email" type="email" placeholder="user@example.com"'
           + ' style="width:100%;box-sizing:border-box;background:rgba(255,255,255,0.07);border:1px solid var(--line);'
           + 'border-radius:6px;padding:7px 10px;color:var(--ink);font-size:0.88rem;font-family:inherit;"></div>';
        h += '<div style="flex:1;min-width:130px;">'
           + '<label style="display:block;font-size:0.7rem;color:var(--ink-muted);margin-bottom:4px;">Role</label>'
           + '<select id="ac-role" style="width:100%;box-sizing:border-box;background:rgba(255,255,255,0.07);'
           + 'border:1px solid var(--line);border-radius:6px;padding:7px 10px;color:var(--ink);font-size:0.88rem;font-family:inherit;">';
        ROLES.forEach(function(r) {
          h += '<option value="' + r + '">' + (ROLE_LABELS[r] || r) + '</option>';
        });
        h += '</select></div>';
        h += '<div style="flex:2;min-width:160px;">'
           + '<label style="display:block;font-size:0.7rem;color:var(--ink-muted);margin-bottom:4px;">Display Name (optional)</label>'
           + '<input id="ac-name" type="text" placeholder="Full name"'
           + ' style="width:100%;box-sizing:border-box;background:rgba(255,255,255,0.07);border:1px solid var(--line);'
           + 'border-radius:6px;padding:7px 10px;color:var(--ink);font-size:0.88rem;font-family:inherit;"></div>';
        h += '<button type="button" onclick="Modules._accessSave()"'
           + ' style="white-space:nowrap;background:var(--accent);color:var(--ink-inverse);border:none;border-radius:6px;'
           + 'padding:8px 20px;font-weight:600;font-size:0.88rem;cursor:pointer;font-family:inherit;">Save</button>';
        h += '</div></div>';

        // ── Current access list table ──────────────────────────────────
        // Client-side pagination
        var pg = _pgState('access');
        var start = pg.page * pg.size;
        var pageSlice = rows.slice(start, start + pg.size);
        pg.count   = pageSlice.length;
        pg.hasMore = start + pg.size < rows.length;
        pg.total   = rows.length;
        if (!rows.length) {
          h += _empty('\uD83D\uDD10', 'No access entries', 'Add the first user above.');
        } else {
          h += '<table class="data-table"><thead><tr>'
             + '<th>Email</th><th>Display Name</th><th>Role</th><th>Active</th><th>Updated</th><th></th>'
             + '</tr></thead><tbody>';
          pageSlice.forEach(function(r) {
            var ee = _e(r.email);
            var isActive = String(r.active || 'FALSE').toUpperCase() === 'TRUE';
            h += '<tr>';
            h += '<td data-label="Email" style="font-size:0.82rem;">' + ee + '</td>';
            h += '<td data-label="Display Name">' + _e(r.displayName || '\u2014') + '</td>';
            h += '<td data-label="Role">' + _rSel(r.email, r.role) + '</td>';
            h += '<td data-label="Active">' + _badge(isActive ? 'Active' : 'Inactive', isActive ? 'success' : 'warn') + '</td>';
            h += '<td data-label="Updated" style="font-size:0.76rem;color:var(--ink-muted);">' + _e(_dateStr(r.updatedAt) || '\u2014') + '</td>';
            h += '<td><button type="button" onclick="Modules._accessRemove(\'' + ee + '\')"'
               + ' style="background:none;border:1px solid var(--danger);border-radius:5px;padding:3px 10px;'
               + 'font-size:0.74rem;cursor:pointer;color:var(--danger);">Remove</button></td>';
            h += '</tr>';
          });
          h += '</tbody></table>';

          // Role legend
          h += '<div style="margin-top:16px;display:flex;flex-wrap:wrap;gap:8px;font-size:0.74rem;color:var(--ink-muted);">';
          ROLES.forEach(function(r) {
            h += _badge((ROLE_LABELS[r] || r), ROLE_COLOR[r] || 'info') + ' ';
          });
          h += '</div>';
          h += _pagerBar('access');
        }

        _body(el, h);
      } catch (e) { _body(el, _errHtml(e.message)); }
    }

    // ── Public action handlers (called from inline onclick) ────────────

    Modules._accessSave = async function() {
      var email = (document.getElementById('ac-email') || {}).value || '';
      var role  = (document.getElementById('ac-role')  || {}).value || 'readonly';
      var name  = (document.getElementById('ac-name')  || {}).value || '';
      email = email.trim().toLowerCase();
      if (!email) { _toast('Email is required.', 'warn'); return; }
      try {
        await (_isFirebaseComms() ? UpperRoom.setAccess({ email: email, role: role, displayName: name }) : TheVine.flock.access.set({ email: email, role: role, displayName: name }));
        _invalidateCache('access-list');
        _toast('Access updated for ' + email, 'success');
        await _render();
      } catch (e) { _toast('Error: ' + (e.message || e), 'danger'); }
    };

    Modules._accessSetRole = async function(email, role) {
      try {
        await (_isFirebaseComms() ? UpperRoom.setAccess({ email: email, role: role }) : TheVine.flock.access.set({ email: email, role: role }));
        _invalidateCache('access-list');
        _toast('Role updated', 'success');
        await _render();
      } catch (e) { _toast('Error setting role: ' + (e.message || e), 'danger'); }
    };

    Modules._accessRemove = async function(email) {
      if (!confirm('Remove access for ' + email + '? This cannot be undone.')) return;
      try {
        await (_isFirebaseComms() ? UpperRoom.removeAccess({ email: email }) : TheVine.flock.access.remove({ email: email }));
        _invalidateCache('access-list');
        _toast('Access removed', 'warn');
        await _render();
      } catch (e) { _toast('Error: ' + (e.message || e), 'danger'); }
    };

    await _render();
  });


