  // Save comms mode to Firestore and invalidate the cached mode
  async function _commsSetMode(mode) {
    var statusEl = document.getElementById('comms-mode-status');
    if (statusEl) statusEl.textContent = 'Saving…';
    try {
      await UpperRoom.setCommsMode(mode);
      _commsMode = mode; // update cached value immediately
      if (statusEl) statusEl.textContent = 'Saved! Reload the Messages tab to apply.';
    } catch (e) {
      if (statusEl) statusEl.textContent = 'Error: ' + e.message;
    }
  }

  function _bulkPreview(input) {
    const file    = input.files && input.files[0];
    const preview = document.getElementById('bulk-preview');
    if (!file || !preview) return;
    const reader  = new FileReader();
    reader.onload = ev => {
      const lines = (ev.target.result || '').split('\n').filter(l => l.trim());
      const cnt   = Math.max(0, lines.length - 1); // subtract header row
      preview.textContent = cnt + ' record' + (cnt !== 1 ? 's' : '') + ' found in file \u2014 ready to import.';
    };
    reader.readAsText(file);
  }

  async function _bulkImport() {
    // API: bulk.membersImport({ records: JSON_array_string })
    // records must be a JSON-stringified array; each record needs firstName + lastName at minimum
    const input  = document.getElementById('bulk-csv-input');
    const status = document.getElementById('bulk-preview');
    if (!input || !input.files || !input.files[0]) { _toast('Please select a CSV file first.', 'warn'); return; }
    if (!confirm('Import members from this file? Records will be created or skipped if they already exist.')) return;
    const file   = input.files[0];
    const reader = new FileReader();
    reader.onload = async ev => {
      const csvText = ev.target.result || '';
      try {
        // Parse CSV client-side: first line = headers, remaining = data rows
        const lines = csvText.split(/\r?\n/).map(l => l.trim()).filter(Boolean);
        if (lines.length < 2) { if (status) status.textContent = 'File has no data rows.'; return; }
        const parseCsvRow = line => line.split(',').map(f => f.replace(/^"|"$/g, '').trim());
        const headers = parseCsvRow(lines[0]).map(h => h.toLowerCase().replace(/\s+/g, ''));
        // Map common CSV column names to API field names
        const fieldMap = {
          firstname: 'firstName', lastname: 'lastName', email: 'email',
          phone: 'cellPhone', cellphone: 'cellPhone', mobile: 'cellPhone',
          status: 'status', homephone: 'homePhone', address: 'addressLine1',
          city: 'city', state: 'state', zip: 'zip', zipcode: 'zip',
          birthdate: 'birthDate', birthday: 'birthDate', gender: 'gender',
          preferredname: 'preferredName', nickname: 'preferredName',
          membernumber: 'memberNumber', householdcode: 'householdCode'
        };
        const records = [];
        for (let i = 1; i < lines.length; i++) {
          const vals = parseCsvRow(lines[i]);
          const obj  = {};
          headers.forEach((h, idx) => { if (vals[idx] !== undefined) obj[fieldMap[h] || h] = vals[idx]; });
          if (obj.firstName || obj.lastName) records.push(obj);
        }
        if (!records.length) {
          if (status) status.textContent = 'No valid records found. CSV must have firstName and lastName columns.';
          return;
        }
        if (status) status.textContent = 'Importing ' + records.length + ' record(s)\u2026';
        const res     = await (_isFirebaseComms() ? UpperRoom.bulkMembersImport({ records: JSON.stringify(records) }) : TheVine.flock.bulk.membersImport({ records: JSON.stringify(records) }));
        const created = res && res.created != null ? res.created : '?';
        const errs    = res && res.errors && res.errors.length ? ' (' + res.errors.length + ' errors)' : '';
        if (status) status.textContent = 'Import complete: ' + created + ' created' + errs + '.';
        _toast('Import complete', 'success');
        _invalidateCache('members');
      } catch (e) {
        if (status) status.textContent = 'Error: ' + e.message;
        _toast('Import failed: ' + e.message, 'danger');
      }
    };
    reader.readAsText(file);
  }

  async function _bulkExport(type) {
    // API: bulk.dataExport({ tab: 'Members' }) — tab must match exact sheet tab name
    // Allowed tabs: Members, Giving, GivingPledges, VolunteerSchedule, Attendance, Events, etc.
    const tabMap = {
      members:    'Members',
      giving:     'Giving',
      pledges:    'GivingPledges',
      volunteers: 'VolunteerSchedule',
      attendance: 'Attendance',
      events:     'Events',
    };
    const tabName  = tabMap[type] || type || 'Members';
    const statusEl = document.getElementById('bulk-export-status');
    if (statusEl) statusEl.textContent = 'Preparing \u201c' + tabName + '\u201d export\u2026';
    try {
      // API returns { tab, headers, rows[] } — convert to CSV and trigger download
      const res = await (_isFirebaseComms() ? UpperRoom.bulkDataExport({ tab: tabName }) : TheVine.flock.bulk.dataExport({ tab: tabName }));
      if (res && res.headers && Array.isArray(res.rows)) {
        const csvLines = [res.headers.join(',')];
        res.rows.forEach(row => {
          const vals = Array.isArray(row) ? row : res.headers.map(h => row[h] != null ? row[h] : '');
          csvLines.push(vals.map(v => '"' + String(v || '').replace(/"/g, '""') + '"').join(','));
        });
        const blob   = new Blob([csvLines.join('\n')], { type: 'text/csv' });
        const anchor = document.createElement('a');
        anchor.href     = URL.createObjectURL(blob);
        anchor.download = 'flockos-' + tabName.toLowerCase() + '-' + new Date().toISOString().substring(0, 10) + '.csv';
        anchor.click();
        if (statusEl) statusEl.textContent = tabName + ' export downloaded (' + res.rows.length + ' rows).';
      } else if (res && res.url) {
        window.open(res.url, '_blank');
        if (statusEl) statusEl.textContent = 'Export ready \u2014 download started.';
      } else {
        if (statusEl) statusEl.textContent = 'Export sent \u2014 check your email for the file.';
      }
    } catch (e) {
      if (statusEl) statusEl.textContent = 'Error: ' + e.message;
      _toast('Export failed: ' + e.message, 'danger');
    }
  }

