  // ═══════════════════════════════════════════════════════════════════════
  // THEMES  (admin-only unless custom themes enabled)
  // ═══════════════════════════════════════════════════════════════════════
  _def('themes', async (el, session) => {
    _shell(el, 'Themes', 'Theme customization is managed by the administrator.', '');
    try {
      // Check if admin allows custom themes
      let allowCustom = false;
      try {
        const cfgRes = await (_isFirebaseComms() ? UpperRoom.listAppConfig() : TheVine.flock.config.list());
        const cfgRows = _rows(cfgRes);
        const acRow = cfgRows.find(r => (r.key || r.configKey) === 'ALLOW_CUSTOM_THEMES');
        if (acRow) allowCustom = String(acRow.value || 'FALSE').toUpperCase() === 'TRUE';
      } catch (_) { /* no auth or config unavailable — default OFF */ }

      let html = '';

      if (!allowCustom) {
        html += '<div style="padding:20px 22px;border-radius:12px;background:var(--bg-sunken);border:1px solid var(--border);font-size:0.92rem;margin-bottom:20px;text-align:center;">';
        html += '<div style="font-size:1.6rem;margin-bottom:8px;">\uD83C\uDFA8</div>';
        html += '<div style="font-weight:600;margin-bottom:4px;">Theme Managed by Administrator</div>';
        html += '<div style="color:var(--ink-muted);font-size:0.84rem;">The site-wide theme is set by your church administrator. Personal theme customization is not currently available.</div>';
        html += '</div>';
        _body(el, html);
        return;
      }

      const tmMeta = (typeof Adornment !== 'undefined' && Adornment.themeMeta) ? Adornment.themeMeta : {};
      const themeList = (typeof Adornment !== 'undefined' && Adornment.themes) ? Adornment.themes.filter(t => t !== 'auto') : [];
      const currentTheme = (typeof Adornment !== 'undefined') ? Adornment.getTheme() : 'america';

      // ── Section 1: My Theme ─────────────────────────────────────────
      html += '<div class="settings-section">';
      html += '<div class="settings-section-header">';
      html += '<span class="settings-section-icon">\u2728</span>';
      html += '<div><h3 class="settings-section-title">My Theme</h3>';
      html += '<p class="settings-section-desc">Choose your personal color theme. Click a swatch to apply instantly.</p></div>';
      html += '</div>';
      html += '<div class="settings-card">';
      html += '<div class="settings-swatch-grid">';
      themeList.forEach(t => {
        const m = tmMeta[t] || {};
        const isCurrent = (currentTheme === t);
        html += '<div class="settings-swatch' + (isCurrent ? ' active' : '') + '" onclick="Modules.setPersonalTheme(\'' + t + '\')">'
              + '<div class="settings-swatch-preview" style="background:linear-gradient(135deg,' + (m.bg || '#111') + ' 60%,' + (m.accent || '#888') + ');"></div>'
              + '<div class="settings-swatch-label">' + _e(m.label || t) + '</div>'
              + '<div class="settings-swatch-mode">' + _e(m.mode || '') + '</div>'
              + '</div>';
      });
      html += '</div></div></div>';

      _body(el, html);
    } catch (e) { _body(el, _errHtml(e.message)); }
  });


