  async function attendanceSummary() {
    try {
      const res = _isFirebaseComms() ? await UpperRoom.attendanceSummary() : await TheVine.flock.attendance.summary({});
      const months = (res && res.summary) ? res.summary : [];
      const totals = (res && res.totals)  ? res.totals  : {};
      _modal('Attendance Summary', [], () => Promise.resolve());
      const form = document.getElementById('ml-modal-form');
      if (form) {
        let html = '';
        // Grand totals ribbon
        if (totals.total) {
          html += '<div class="flock-dashboard-strip" style="margin-bottom:16px;">';
          html += '<div class="flock-dash-item"><span class="flock-dash-val">' + _e(String(totals.services || 0)) + '</span><span class="flock-dash-label">Services</span></div>';
          html += '<div class="flock-dash-item"><span class="flock-dash-val">' + _e(String(totals.total || 0)) + '</span><span class="flock-dash-label">Total</span></div>';
          html += '<div class="flock-dash-item"><span class="flock-dash-val">' + _e(String(totals.avgPerService || 0)) + '</span><span class="flock-dash-label">Avg / Service</span></div>';
          html += '<div class="flock-dash-item"><span class="flock-dash-val">' + _e(String(totals.adults || 0)) + '</span><span class="flock-dash-label">Adults</span></div>';
          html += '<div class="flock-dash-item"><span class="flock-dash-val">' + _e(String(totals.children || 0)) + '</span><span class="flock-dash-label">Children</span></div>';
          html += '</div>';
        }
        // Monthly breakdown table
        if (months.length) {
          html += '<table class="data-table"><thead><tr><th>Month</th><th>Services</th><th>Adults</th><th>Children</th><th>Total</th><th>Avg</th></tr></thead><tbody>';
          months.forEach(m => {
            html += '<tr><td>' + _e(m.month) + '</td><td>' + _e(String(m.services)) + '</td>'
                  + '<td>' + _e(String(m.adults)) + '</td><td>' + _e(String(m.children)) + '</td>'
                  + '<td><strong>' + _e(String(m.total)) + '</strong></td>'
                  + '<td>' + _e(String(m.avgPerService)) + '</td></tr>';
          });
          html += '</tbody></table>';
        } else {
          html += '<p style="color:var(--ink-muted);text-align:center;padding:24px 0;">No attendance data yet.</p>';
        }
        form.innerHTML = html;
      }
    } catch (e) { _toast(e.message, 'warn'); }
  }

