  function _sermonReviewNew() {
    const sermons     = _dataCache['sermons'] || [];
    const opts        = sermons.map(s => s.title || s.name || String(s.id || ''));
    const ids         = sermons.map(s => String(s.id || ''));
    const defaultSid  = _reviewSermonId || (ids.length ? ids[0] : '');
    const defaultIdx  = ids.indexOf(defaultSid);
    _modal('Write Sermon Review', [
      { name: 'sermonId',     label: 'Sermon',        type: 'select',   options: opts.length ? opts : ['(no sermons loaded)'],
        value: defaultIdx >= 0 ? opts[defaultIdx] : '' },
      { name: 'decision',     label: 'Decision',      type: 'select',   options: ['Approved', 'Needs Revision', 'Feedback Only'], required: true },
      { name: 'feedback',     label: 'Feedback',      type: 'textarea' },
      { name: 'reviewerName', label: 'Reviewer Name', type: 'text' },
      { name: 'privateNotes', label: 'Private Notes', type: 'textarea' },
    ], async data => {
      // Map display title -> sermonId
      const idx = opts.indexOf(data.sermonId);
      if (idx >= 0) data.sermonId = ids[idx];
      else if (!data.sermonId && defaultSid) data.sermonId = defaultSid;
      if (_isFirebaseComms()) { await UpperRoom.createSermonReview(data); }
      else { await TheVine.flock.sermonReviews.create(data); }
      sermonView('reviews');
    });
  }

