  async function _discViewAssessment(id) {
    let r = (_dataCache['disc-assessments'] || []).find(a => a.id === id);
    if (!r) {
      try { r = await (_isFirebaseComms() ? UpperRoom.getDiscAssessment({ id }) : TheVine.flock.discipleship.assessments.get({ id })); }
      catch (e) { _toast(e.message, 'warn'); return; }
    }
    const scoreHtml = (r.scoreTotal && r.scoreMax)
      ? '<div style="display:flex;align-items:center;gap:10px;margin:10px 0;">'
        + '<div style="flex:1;height:8px;background:var(--bg-sunken);border-radius:4px;">'
        + '<div style="width:' + Math.min(100, Number(r.scorePercent||0)) + '%;height:8px;background:var(--accent);border-radius:4px;"></div>'
        + '</div><span style="font-size:0.85rem;font-weight:700;">' + _e(String(r.scorePercent||0)) + '%</span></div>'
      : '';
    const html = '<div style="line-height:1.65;font-size:0.88rem;">'
      + '<div style="margin-bottom:5px;"><strong>Member:</strong> ' + _e(r.memberName || '') + '</div>'
      + '<div style="margin-bottom:5px;"><strong>Type:</strong> ' + _e(r.assessmentType || '') + '</div>'
      + '<div style="margin-bottom:5px;"><strong>Date:</strong> ' + _e(r.dateTaken || '') + '</div>'
      + scoreHtml
      + (r.topGifts ? '<div style="margin-top:10px;"><strong>Top Gifts / Strengths:</strong><div style="margin-top:4px;color:var(--accent);">' + _e(r.topGifts) + '</div></div>' : '')
      + (r.growthAreas ? '<div style="margin-top:10px;"><strong>Growth Areas:</strong><div style="margin-top:4px;color:var(--ink-muted);">' + _e(r.growthAreas) + '</div></div>' : '')
      + (r.recommendations ? '<div style="margin-top:10px;"><strong>Recommendations:</strong><div style="margin-top:4px;">' + _e(r.recommendations) + '</div></div>' : '')
      + (r.notes ? '<div style="margin-top:10px;"><strong>Notes:</strong><div style="margin-top:4px;color:var(--ink-muted);">' + _e(r.notes) + '</div></div>' : '')
      + '</div>';
    _modal(_e(r.assessmentName || 'Assessment'), [{ type: 'html', html }], () => {}, 'Close');
  }

