  // ── Client-side filters ──────────────────────────────────────────────────
  function _discFilterPaths() {
    const q     = ((document.getElementById('disc-path-search') || {}).value || '').toLowerCase();
    const stat  = ((document.getElementById('disc-path-status') || {}).value || '').toLowerCase();
    const level = ((document.getElementById('disc-path-level')  || {}).value || '').toLowerCase();
    const rows  = _dataCache['disc-paths'] || [];
    const grid  = document.getElementById('disc-path-grid');
    if (!grid) return;
    grid.innerHTML = '';
    rows.filter(r => {
      if (stat  && String(r.status||'').toLowerCase() !== stat) return false;
      if (level && String(r.difficultyLevel||'').toLowerCase() !== level) return false;
      if (q && !(r.name||'').toLowerCase().includes(q) && !(r.category||'').toLowerCase().includes(q)) return false;
      return true;
    }).forEach(r => { grid.innerHTML += _discPathCard(r); });
  }

  function _discFilterEnrollments() {
    const q    = ((document.getElementById('disc-enroll-search') || {}).value || '').toLowerCase();
    const stat = ((document.getElementById('disc-enroll-status') || {}).value || '').toLowerCase();
    const rows = _dataCache['disc-enrollments'] || [];
    const tbl  = document.getElementById('disc-enroll-table');
    if (!tbl) return;
    const filtered = rows.filter(r => {
      if (stat && String(r.status||'').toLowerCase() !== stat) return false;
      if (q && !(r.memberName||'').toLowerCase().includes(q) && !(r.pathName||'').toLowerCase().includes(q)) return false;
      return true;
    });
    tbl.innerHTML = _table(
      ['Member', 'Path', 'Progress', 'Steps', 'Facilitator', 'Status', ''],
      filtered.map(r => [
        _e(r.memberName || ''),
        _e(r.pathName || ''),
        '<div style="display:flex;align-items:center;gap:6px;"><div style="width:55px;height:5px;background:var(--bg-sunken);border-radius:3px;"><div style="width:' + Math.min(100, Number(r.percentComplete||0)) + '%;height:5px;background:var(--accent);border-radius:3px;"></div></div><span style="font-size:0.72rem;color:var(--ink-muted);white-space:nowrap;">' + _e(String(r.percentComplete||0)) + '%</span></div>',
        _e(String(r.stepsCompleted||0) + '/' + String(r.totalSteps||0)),
        _e(r.facilitatorName || ''),
        _statusBadge(r.status),
        '<span style="display:inline-flex;gap:4px;"><button onclick="Modules._discAdvanceEnrollment(\'' + _e(String(r.id)) + '\')" style="font-size:0.72rem;padding:3px 8px;border:1px solid var(--line);border-radius:5px;background:none;color:var(--accent);cursor:pointer;">▶ Next</button><button onclick="Modules._discEditEnrollment(\'' + _e(String(r.id)) + '\')" style="font-size:0.72rem;padding:3px 8px;border:1px solid var(--line);border-radius:5px;background:none;color:var(--ink-muted);cursor:pointer;">✏</button></span>',
      ])
    );
  }

