  async function newMessage() {
    var b = document.querySelector('#view-comms #ml-body');
    if (b) b.innerHTML = _spinner();
    const dir = await _ensureMemberDir();
    const mOpts = _memberOpts(dir);
    _modal('&#9993;  Compose Message', [
      { name: 'recipientId', label: 'To',       type: 'select', options: mOpts, required: true },
      { name: 'subject',     label: 'Subject',  required: true },
      { name: 'body',        label: 'Message',  type: 'textarea', required: true, rows: 8 },
      { name: 'priority',    label: 'Priority', type: 'select',
        options: ['Normal','High','Urgent'] },
    ], async data => {
      data.recipientType = 'Member';
      if (_isFirebaseComms()) { await UpperRoom.createThread(data.subject, [data.recipientId], data.body); }
      else { await TheVine.flock.comms.messages.send(data); }
      _reload('comms');
    }, 'Send Message');
  }

  function replyMessage(msgId, cache) {
    const rows = _dataCache['comms-' + cache] || [];
    const msg = rows.find(r => r.id === msgId || String(r.id) === msgId);
    if (!msg) { _toast('Message not found. Refresh and try again.', 'warn'); return; }
    const sender = msg.senderName || msg.senderEmail || 'Unknown';
    const quoted = (msg.body || '').split('\n').map(l => '> ' + l).join('\n');

    _modal('&#8617;  Reply to ' + sender, [
      { name: '_quote', label: 'Original Message', type: 'html',
        html: '<div style="background:rgba(255,255,255,0.04);border-left:3px solid var(--accent);'
          + 'padding:10px 14px;border-radius:0 6px 6px 0;font-size:0.82rem;color:var(--ink-muted);'
          + 'white-space:pre-wrap;max-height:140px;overflow-y:auto;line-height:1.5;margin-bottom:4px;">'
          + _e(msg.body || '') + '</div>' },
      { name: 'body', label: 'Your Reply', type: 'textarea', required: true, rows: 6 },
    ], async data => {
      if (_isFirebaseComms()) {
        await UpperRoom.sendMessage(msg.threadId || msg.id, data.body + '\n\n' + quoted);
      } else {
        await TheVine.flock.comms.messages.send({
          threadId:      msg.threadId,
          recipientId:   msg.senderEmail || msg.senderId,
          recipientName: msg.senderName || '',
          recipientType: 'Member',
          subject:       'Re: ' + (msg.subject || '').replace(/^Re:\s*/i, ''),
          body:          data.body + '\n\n' + quoted,
          replyToId:     msg.id,
        });
      }
      _commsOpenMsg = null;
      _reload('comms');
    }, 'Send Reply');
  }

  async function forwardMessage(msgId, cache) {
    const rows = _dataCache['comms-' + cache] || [];
    const msg = rows.find(r => r.id === msgId || String(r.id) === msgId);
    if (!msg) { _toast('Message not found. Refresh and try again.', 'warn'); return; }
    var b = document.querySelector('#view-comms #ml-body');
    if (b) b.innerHTML = _spinner();
    const dir = await _ensureMemberDir();
    const mOpts = _memberOpts(dir);
    const fwdBody = '\n\n--- Forwarded message ---\n'
      + 'From: ' + (msg.senderName || msg.senderEmail || '') + '\n'
      + 'Subject: ' + (msg.subject || '') + '\n\n'
      + (msg.body || '');
    _modal('&#8618;  Forward Message', [
      { name: 'recipientId', label: 'To',      type: 'select', options: mOpts, required: true },
      { name: 'subject',     label: 'Subject', value: 'Fwd: ' + (msg.subject || '').replace(/^Fwd:\s*/i, '') },
      { name: 'body',        label: 'Message', type: 'textarea', required: true, value: fwdBody, rows: 8 },
    ], async data => {
      data.recipientType = 'Member';
      if (_isFirebaseComms()) { await UpperRoom.createThread(data.subject, [data.recipientId], data.body); }
      else { await TheVine.flock.comms.messages.send(data); }
      _commsOpenMsg = null;
      _reload('comms');
    }, 'Forward');
  }

  function sendSms() {
    _modal('&#128242;  Send SMS', [
      { name: 'phone',   label: 'Phone Number', type: 'tel', required: true },
      { name: 'message', label: 'Message',      type: 'textarea', required: true, rows: 4 },
    ], async data => {
      const phone = data.phone.replace(/[^\d+]/g, '');
      const body  = data.message.trim();
      if (!phone || !body) return;

      // Check if Twilio gateway is enabled (cached from config.list on Control Panel load)
      var cfgRows = _dataCache['config'] || [];
      // Lazy-load config if not yet cached (user hasn't visited Control Panel)
      if (!cfgRows.length) {
        try {
          var res = await (_isFirebaseComms() ? UpperRoom.listAppConfig() : TheVine.flock.config.list());
          cfgRows = _rows(res);
          _dataCache['config'] = cfgRows;
        } catch (_) { /* offline or no auth — fall through to native */ }
      }
      var twilRow = cfgRows.find(r => (r.key || r.configKey) === 'TWILIO_ENABLED');
      var twilioOn = twilRow && String(twilRow.value).toUpperCase() === 'TRUE';

      if (twilioOn) {
        try {
          await TheVine.flock.sms.send({ phone: phone, message: body });
          _toast('📱 SMS sent to ' + phone);
        } catch (e) {
          _toast('SMS send failed: ' + e.message, 'danger');
        }
      } else {
        window.open('sms:' + phone + '?body=' + encodeURIComponent(body), '_self');
      }
    }, 'Send SMS');
  }

  function newBroadcast() {
    _modal('&#128227;  New Broadcast', [
      { name: 'subject',  label: 'Subject',  required: true },
      { name: 'body',     label: 'Message',  type: 'textarea', required: true, rows: 6 },
      { name: 'audience', label: 'Send To',  type: 'select',
        options: ['All Members','Volunteers','Leaders','Admins'] },
    ], async data => {
      data.audience = (data.audience || 'all').toLowerCase().replace(/\s+/g, '').replace('allmembers','all');
      if (_isFirebaseComms()) { await UpperRoom.createBroadcast(data); }
      else { await TheVine.flock.comms.broadcast.create(data); }
      // Self-notification so the sender receives delivery confirmation in their bell
      try {
        const session = (typeof Nehemiah !== 'undefined') ? Nehemiah.getSession() : null;
        const senderEmail = session && session.email ? session.email : null;
        if (senderEmail) {
          if (_isFirebaseComms()) {
            await UpperRoom.createNotification(senderEmail, '✅ Broadcast sent: ' + (data.subject || ''),
              'Your broadcast to “' + (data.audience || 'all') + '” was sent successfully.', 'broadcast');
          } else {
            await TheVine.flock.comms.notifications.create({
              recipientEmail: senderEmail,
              subject: '✅ Broadcast sent: ' + (data.subject || ''),
              body: 'Your broadcast to “' + (data.audience || 'all') + '” was sent successfully.',
              entityType: 'broadcast',
              notifType: 'broadcast',
              status: 'Unread',
            });
          }
          if (typeof refreshNotifBadge === 'function') refreshNotifBadge();
        }
      } catch (_) {}
      _reload('comms');
    }, 'Send Broadcast');
  }

