  // ── Missions: filter country grid ─────────────────────────────────────
  function _missionsFilter() {
    const q    = (document.getElementById('missions-search')     || {}).value || '';
    const pers = (document.getElementById('missions-pers-filter')||{}).value || '';
    const acc  = (document.getElementById('missions-access-filter')||{}).value || '';
    const grid = document.getElementById('missions-grid');
    if (!grid) return;
    const cards = grid.children;
    for (const card of cards) {
      const text  = card.textContent.toLowerCase();
      const show  = (!q || text.includes(q.toLowerCase()))
                 && (!pers || text.includes(pers.toLowerCase()))
                 && (!acc  || text.includes(acc.toLowerCase()));
      card.style.display = show ? '' : 'none';
    }
  }

  // ── Missions: open country detail ─────────────────────────────────────
  function openCountry(id) {
    const cache = _dataCache['missions-world'] || [];
    const rec   = cache.find(r => String(r.id) === String(id));
    if (!rec) return;

    const rows = [
      ['Country Name',        rec.countryName || rec.name || '—'],
      ['ISO Code',            rec.isoCode || '—'],
      ['Continent',           rec.continent || '—'],
      ['Persecution Level',   rec.persecutionLevel || '—'],
      ['Persecution Rank',    rec.persecutionRank || '—'],
      ['Gospel Access',       rec.gospelAccess || '—'],
      ['10/40 Window',        rec.tenFortyWindow || rec['10/40Window'] || '—'],
      ['Dominant Religion',   rec.dominantReligion || '—'],
      ['Population',          rec.population ? Number(rec.population).toLocaleString() : '—'],
      ['% Evangelical',       rec.percentEvangelical ? rec.percentEvangelical + '%' : '—'],
      ['Unreached Groups',    rec.unreachedGroups || '—'],
      ['Freedom Index',       rec.freedomIndex || '—'],
      ['Notes',               rec.notes || '—'],
    ];

    const tableHtml = '<table style="width:100%;border-collapse:collapse;font-size:0.83rem;">'
      + rows.map(([k,v]) => '<tr><td style="padding:7px 10px;border-bottom:1px solid var(--line);color:var(--ink-muted);font-weight:600;width:45%;vertical-align:top;">' + _e(k) + '</td><td style="padding:7px 10px;border-bottom:1px solid var(--line);">' + _e(String(v)) + '</td></tr>').join('')
      + '</table>';

    const editBtn = '<button onclick="const mx=document.getElementById(\'ml-modal-x\');if(mx)mx.click();Modules.editMissionsCountry(\'' + _e(id) + '\')" style="background:none;border:1px solid var(--line);border-radius:6px;padding:6px 14px;font-size:0.80rem;cursor:pointer;color:var(--ink);">✏️ Edit</button>';

    _modal((rec.icon || '🌍') + ' ' + (rec.countryName || rec.name || 'Country'),
      [], () => Promise.resolve());
    const form = document.getElementById('ml-modal-form');
    if (form) {
      form.innerHTML = tableHtml
        + '<div style="margin-top:14px;display:flex;gap:8px;">'
        + editBtn
        + '</div>';
    }
  }

