  async function _givingStatement() {
    const memberInput = (document.getElementById('stmt-member') || {}).value || '';
    const year        = (document.getElementById('stmt-year')   || {}).value || String(new Date().getFullYear());
    const resultEl    = document.getElementById('stmt-result');
    if (!memberInput) { if (resultEl) resultEl.innerHTML = '<p style="color:var(--danger);font-size:0.85rem;">Please enter a member name or email.</p>'; return; }
    if (resultEl) resultEl.innerHTML = '<p style="font-size:0.85rem;color:var(--ink-muted);">Loading…</p>';
    try {
      // Resolve display name → memberId (email or UUID) from cached directory
      const dir  = _dataCache['memberDir'] || [];
      let memberId = memberInput;
      const found  = dir.find(m => {
        const nm = ((m.preferredName || m.firstName || '') + ' ' + (m.lastName || '')).trim();
        return nm.toLowerCase() === memberInput.toLowerCase() ||
               (m.email || '').toLowerCase() === memberInput.toLowerCase();
      });
      if (found) memberId = found.email || found.id || memberInput;

      // API: handleGivingMemberStatement expects { memberId, year }
      // Returns: { memberId, year, totalGiven, records[] }
      const res   = await (_isFirebaseComms() ? UpperRoom.memberGivingStatement({ memberId: memberId, year: year }) : TheVine.flock.giving.memberStatement({ memberId, year }));
      const mName = (found ? ((found.preferredName || found.firstName || '') + ' ' + (found.lastName || '')).trim() : '') || memberInput;
      const totalGiven = res && res.totalGiven != null ? Number(res.totalGiven) : 0;
      const records    = (res && Array.isArray(res.records)) ? res.records : [];
      if (!resultEl) return;
      let html = '<div style="background:var(--bg-raised);border:1px solid var(--line);border-radius:10px;padding:20px;margin-top:4px;">';
      html += '<div style="font-weight:700;font-size:1rem;margin-bottom:4px;">' + _e(mName) + '</div>';
      html += '<div style="font-size:0.76rem;color:var(--ink-muted);margin-bottom:16px;">Giving Statement &mdash; ' + _e(year) + '</div>';
      html += '<div style="display:flex;gap:10px;flex-wrap:wrap;margin-bottom:16px;">'
        + _mStat('Gifts',       String(records.length), 'var(--accent)')
        + _mStat('Total Given', '$' + totalGiven.toLocaleString(), 'var(--success)')
        + '</div>';
      if (records.length) {
        html += _table(
          ['Date', 'Fund', 'Method', 'Amount', 'Tax Ded.', 'Notes'],
          records.map(g => [
            _e(g.date || ''),
            _e(g.fund || 'General'),
            _e(g.method || ''),
            g.amount ? '$' + Number(g.amount).toFixed(2) : '',
            g.isTaxDeductible ? '✓' : '',
            _e((g.notes || '').substring(0, 40)),
          ])
        );
      } else {
        html += '<p style="font-size:0.85rem;color:var(--ink-muted);">No gifts recorded for this year.</p>';
      }
      html += '</div>';
      html += '<div style="text-align:right;margin-top:10px;"><button type="button" onclick="Modules._givingStatementPrint()" '
        + 'style="background:var(--accent);color:var(--ink-inverse);border:none;border-radius:6px;padding:6px 16px;font-weight:600;font-size:0.8rem;cursor:pointer;font-family:inherit;">📦 Print / PDF</button></div>';
      resultEl.innerHTML = html;
    } catch (e) {
      if (resultEl) resultEl.innerHTML = '<p style="color:var(--danger);font-size:0.85rem;">Error: ' + _e(e.message) + '</p>';
    }
  }


