  // ── Devotional card toggle ──
  function _devToggle(idx) {
    const body = document.getElementById('dev-body-' + idx);
    const chev = document.getElementById('dev-chev-' + idx);
    if (!body) return;
    const open = body.classList.toggle('dev-feed-open');
    if (chev) chev.style.transform = open ? 'rotate(180deg)' : '';
    if (open) body.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
  }

  // ── Devotional load more ──
  function _devLoadMore() {
    const allRows = _dataCache['_devAllRows'] || [];
    const todayIdx = _dataCache['_devToday'] || 0;
    const page = _dataCache['_devPage'] || 30;
    const cap = Math.min(allRows.length - 1, todayIdx + (_dataCache['_devCap'] || 180));
    const shown = _dataCache['_devShown'] || page;
    const renderCard = _dataCache['_devRenderCard'];
    if (!renderCard) return;
    const feed = document.getElementById('dev-feed');
    if (!feed) return;
    const newEnd = Math.min(cap, todayIdx + shown + page);
    let h = '';
    for (let i = todayIdx + shown + 1; i <= newEnd; i++) h += renderCard(i);
    feed.insertAdjacentHTML('beforeend', h);
    _dataCache['_devShown'] = shown + page;
    const loadMore = document.getElementById('dev-load-more');
    if (loadMore) {
      const rem = cap - newEnd;
      if (rem > 0) {
        loadMore.innerHTML = '<a onclick="Modules._devLoadMore()" style="color:var(--accent);font-size:0.92rem;font-weight:600;cursor:pointer;text-decoration:none;">Load More (' + Math.min(rem, page) + ' more days) &#9662;</a>';
      } else {
        loadMore.remove();
      }
    }
  }

  // ── Devotional date navigation (scroll to card) ──
  function _devNav(idx) {
    const card = document.getElementById('dev-card-' + idx);
    if (card) {
      card.scrollIntoView({ behavior: 'smooth', block: 'center' });
      const body = document.getElementById('dev-body-' + idx);
      if (body && !body.classList.contains('dev-feed-open')) _devToggle(idx);
      return;
    }
    const feed = document.getElementById('dev-feed');
    if (feed) feed.scrollIntoView({ behavior: 'smooth' });
  }
  function _devPickDate(isoStr) {
    const d = new Date(isoStr + 'T00:00:00');
    const yr = _dataCache['_devYear'] || d.getFullYear();
    const jan1 = new Date(yr, 0, 1);
    const idx = Math.floor((d - jan1) / 86400000);
    _devNav(idx);
  }

