  // ── Daily Devotional: submit prayer request ──
  async function _devSubmitPrayer(idx) {
    const name  = (document.getElementById('db-prName-'  + idx) || {}).value || '';
    const email = (document.getElementById('db-prEmail-' + idx) || {}).value || '';
    const phone = (document.getElementById('db-prPhone-' + idx) || {}).value || '';
    const text  = (document.getElementById('db-prText-'  + idx) || {}).value || '';
    if (!name.trim() || !text.trim()) { _toast('Please enter your name and prayer request.', 'warn'); return; }
    const cat  = (document.getElementById('db-prCat-'  + idx) || {}).value || '';
    const conf = (document.getElementById('db-prConf-' + idx) || {}).checked || false;
    const fu   = (document.getElementById('db-prFu-'   + idx) || {}).checked || false;
    try {
      var prayerData = {
        submitterName: name.trim(),
        submitterEmail: email.trim(),
        submitterPhone: phone.trim(),
        prayerText: text.trim(),
        category: cat,
        isConfidential: conf,
        followUpRequested: fu
      };
      if (_isFirebaseComms()) { await UpperRoom.createPrayer(prayerData); }
      else { await TheVine.flock.call('prayer.submit', prayerData, { skipAuth: true }); }
      _toast('Your prayer request has been submitted. We are praying with you.');
      _reload('devotionals');
    } catch (e) { _toast('Error submitting prayer: ' + e.message, 'danger'); }
  }

