  function _mpToggleEdit() {
    var v = document.getElementById('mp-view');
    var e = document.getElementById('mp-edit');
    if (!v || !e) return;
    var editing = e.style.display !== 'none';
    v.style.display = editing ? '' : 'none';
    e.style.display = editing ? 'none' : '';
  }

  async function _mpChangePasscode() {
    var curEl  = document.getElementById('mp-curPass');
    var newEl  = document.getElementById('mp-newPass');
    var confEl = document.getElementById('mp-confirmPass');
    var stEl   = document.getElementById('mp-pass-status');
    if (!curEl || !newEl || !confEl) return;
    var cur  = curEl.value;
    var nw   = newEl.value;
    var conf = confEl.value;
    function _pstat(msg, color) { if (stEl) { stEl.textContent = msg; stEl.style.color = color; } }
    if (!cur || !nw || !conf) { _pstat('All fields are required.', 'var(--danger)'); return; }
    if (nw.length < 6) { _pstat('New passcode must be at least 6 characters.', 'var(--danger)'); return; }
    if (nw !== conf) { _pstat('New passcodes do not match.', 'var(--danger)'); return; }
    _pstat('Updating\u2026', 'var(--ink-muted)');
    try {
      await TheVine.john.auth.changePasscode({ currentPasscode: cur, newPasscode: nw });
      _pstat('Passcode updated!', 'var(--success)');
      curEl.value = ''; newEl.value = ''; confEl.value = '';
    } catch (e) {
      _pstat(e.message || 'Failed to update passcode.', 'var(--danger)');
    }
  }

  async function _mpSaveProfile() {
    var session = (typeof TheVine !== 'undefined' ? TheVine.session() : null);
    if (!session) return;
    var data = { email: session.email };

    // Personal
    var pn = document.getElementById('mp-preferredName');
    var gn = document.getElementById('mp-gender');
    var db = document.getElementById('mp-dob');
    var ms = document.getElementById('mp-maritalStatus');
    var sn = document.getElementById('mp-spouseName');
    if (pn) data.preferredName   = pn.value.trim();
    if (gn) data.gender          = gn.value;
    if (db) data.dateOfBirth     = db.value.trim();
    if (ms) data.maritalStatus   = ms.value;
    if (sn) data.spouseName      = sn.value.trim();

    // Contact
    var ph = document.getElementById('mp-phone');
    var hp = document.getElementById('mp-homePhone');
    var wp = document.getElementById('mp-workPhone');
    var se = document.getElementById('mp-secondaryEmail');
    var pc = document.getElementById('mp-preferredContact');
    if (ph) data.cellPhone        = ph.value.trim();
    if (hp) data.homePhone        = hp.value.trim();
    if (wp) data.workPhone        = wp.value.trim();
    if (se) data.secondaryEmail   = se.value.trim();
    if (pc) data.preferredContact = pc.value;

    // Address
    var ad = document.getElementById('mp-addr');
    var a2 = document.getElementById('mp-addr2');
    var ci = document.getElementById('mp-city');
    var st = document.getElementById('mp-state');
    var zi = document.getElementById('mp-zip');
    var co = document.getElementById('mp-country');
    if (ad) data.address1          = ad.value.trim();
    if (a2) data.address2          = a2.value.trim();
    if (ci) data.city              = ci.value.trim();
    if (st) data.state             = st.value.trim();
    if (zi) data.zip               = zi.value.trim();
    if (co) data.country           = co.value.trim();

    // Spiritual & Involvement
    var sg = document.getElementById('mp-spiritualGifts');
    var wb = document.getElementById('mp-website');
    if (sg) data.spiritualGifts   = sg.value.trim();
    if (wb) data.website           = wb.value.trim();

    // Emergency
    var en = document.getElementById('mp-emerg-name');
    var ep = document.getElementById('mp-emerg-phone');
    if (en) data.emergencyContact  = en.value.trim();
    if (ep) data.emergencyPhone    = ep.value.trim();

    try {
      await TheVine.flock.call('members.update', data);
      _toast('Profile updated!', 'success');
      _mpToggleEdit();
      var el = document.getElementById('view-my-profile');
      if (el) { el.dataset.loaded = ''; Modules.render('my-profile', el, session); }
    } catch (e) { _toast('Save failed: ' + e.message, 'danger'); }
  }


  // ═══════════════════════════════════════════════════════════════════════
  // MY GIVING — Self-service giving history (all authenticated users)
  // ═══════════════════════════════════════════════════════════════════════
  _def('my-giving', async (el, session) => {
    _shell(el, 'My Giving', 'Your contribution history and statements.', '');
    try {
      var email = session.email;
      var raw = await TheVine.flock.call('giving.list', { email: email });
      var rows = _rows(raw);

      // Summary stats
      var total = 0, thisYear = 0, yearStr = String(new Date().getFullYear());
      rows.forEach(function(r) {
        var amt = parseFloat(r['Amount']) || 0;
        total += amt;
        if ((r['Date'] || '').indexOf(yearStr) === 0) thisYear += amt;
      });

      var html = '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:12px;margin-bottom:20px;">'
        + '<div style="background:var(--bg-raised);border:1px solid var(--line);border-radius:10px;padding:14px;text-align:center;">'
        + '<div style="font-size:0.75rem;color:var(--ink-muted);">Total Giving</div>'
        + '<div style="font-size:1.4rem;font-weight:700;color:var(--accent);">$' + total.toLocaleString('en-US', {minimumFractionDigits:2}) + '</div></div>'
        + '<div style="background:var(--bg-raised);border:1px solid var(--line);border-radius:10px;padding:14px;text-align:center;">'
        + '<div style="font-size:0.75rem;color:var(--ink-muted);">' + yearStr + ' YTD</div>'
        + '<div style="font-size:1.4rem;font-weight:700;color:var(--accent);">$' + thisYear.toLocaleString('en-US', {minimumFractionDigits:2}) + '</div></div>'
        + '<div style="background:var(--bg-raised);border:1px solid var(--line);border-radius:10px;padding:14px;text-align:center;">'
        + '<div style="font-size:0.75rem;color:var(--ink-muted);">Gifts</div>'
        + '<div style="font-size:1.4rem;font-weight:700;color:var(--accent);">' + rows.length + '</div></div>'
        + '</div>';

      if (!rows.length) {
        html += _empty('&#10070;', 'No giving history yet', '');
      } else {
        html += '<table class="data-table"><thead><tr>'
          + '<th>Date</th><th>Amount</th><th>Fund</th><th>Method</th>'
          + '</tr></thead><tbody>';
        rows.sort(function(a,b) { return (b['Date']||'').localeCompare(a['Date']||''); });
        rows.forEach(function(r) {
          html += '<tr>'
            + '<td>' + _e(r['Date'] || '') + '</td>'
            + '<td style="font-weight:600;">$' + (parseFloat(r['Amount'])||0).toLocaleString('en-US',{minimumFractionDigits:2}) + '</td>'
            + '<td>' + _e(r['Fund'] || r['Category'] || 'General') + '</td>'
            + '<td>' + _e(r['Method'] || '') + '</td>'
            + '</tr>';
        });
        html += '</tbody></table>';
      }

      _body(el, html);
    } catch (e) { _body(el, _errHtml(e.message)); }
  });


  // ══════════════════════════════════════════════════════════════════════════
  // QR CODE GENERATION (Canvas-based, no external library)
  // ══════════════════════════════════════════════════════════════════════════
  function generateQR(text, size) {
    size = size || 200;
    // Use a simple QR encoding via a data URL from a public chart API fallback
    // Primary: try the native BarcodeDetector (Chrome) for reading; for generation
    // we use a lightweight encoder via canvas pixel grid
    var img = document.createElement('img');
    img.width = size; img.height = size;
    img.alt = 'QR Code';
    img.style.cssText = 'border-radius:8px;background:#fff;padding:8px;';
    // Use Google Charts QR (safe, public, no API key)
    img.src = 'https://chart.googleapis.com/chart?cht=qr&chs=' + size + 'x' + size
      + '&chl=' + encodeURIComponent(text) + '&choe=UTF-8';
    return img;
  }

  function showCardQR() {
    var cardId = window._pendingCardId || new URLSearchParams(window.location.search).get('m') || '';
    if (!cardId) return;
    var url = window.location.origin + window.location.pathname + '?m=' + encodeURIComponent(cardId);
    var qr = generateQR(url, 240);
    var overlay = document.createElement('div');
    overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.7);z-index:1001;display:flex;align-items:center;justify-content:center;';
    overlay.innerHTML = '<div style="background:var(--bg-raised);border-radius:12px;padding:24px;text-align:center;">'
      + '<h3 style="color:var(--accent);margin-bottom:12px;font-size:0.92rem;">Scan to view card</h3>'
      + '<div id="qr-holder"></div>'
      + '<p style="color:var(--ink-muted);font-size:0.75rem;margin-top:10px;">' + _e(cardId) + '</p>'
      + '<button onclick="this.closest(\'div[style]\').parentElement.remove()" style="margin-top:12px;background:var(--accent);color:var(--ink-inverse);border:none;border-radius:6px;padding:8px 20px;cursor:pointer;font-size:0.85rem;">Close</button>'
      + '</div>';
    document.body.appendChild(overlay);
    overlay.querySelector('#qr-holder').appendChild(qr);
    overlay.addEventListener('click', function(e) { if (e.target === overlay) overlay.remove(); });
  }

  // ══════════════════════════════════════════════════════════════════════════
  // GEOLOCATION CHECK-IN
  // ══════════════════════════════════════════════════════════════════════════
  function geoCheckin() {
    if (!navigator.geolocation) { _toast('Geolocation is not supported on this device.', 'warn'); return; }
    var btn = event && event.target; if (btn) { btn.disabled = true; btn.textContent = 'Locating\u2026'; }
    navigator.geolocation.getCurrentPosition(
      function(pos) {
        var lat = pos.coords.latitude.toFixed(6);
        var lon = pos.coords.longitude.toFixed(6);
        TheVine.flock.call('attendance.create', {
          serviceType: 'Geo Check-In',
          date: new Date().toISOString().slice(0, 10),
          notes: 'Lat: ' + lat + ', Lon: ' + lon + ' at ' + new Date().toLocaleTimeString()
        }).then(function() {
          if (btn) { btn.textContent = '\u2714 Checked In'; btn.style.background = 'var(--success)'; }
          else _toast('Checked in! (' + lat + ', ' + lon + ')');
        }).catch(function(e) {
          _toast('Check-in failed: ' + (e.message || e), 'danger');
          if (btn) { btn.disabled = false; btn.textContent = '\uD83D\uDCCD Geo Check-In'; }
        });
      },
      function(err) {
        _toast('Location access denied: ' + err.message, 'danger');
        if (btn) { btn.disabled = false; btn.textContent = '\uD83D\uDCCD Geo Check-In'; }
      },
      { enableHighAccuracy: true, timeout: 10000 }
    );
  }

