            + '<div style="flex:1;min-width:0;">'
            + '<div style="font-weight:600;font-size:0.88rem;color:var(--ink);">' + _e(label) + '</div>'
            + '<div style="font-size:0.74rem;color:var(--ink-muted);margin-top:2px;display:flex;gap:10px;flex-wrap:wrap;">'
            + (dLabel ? '<span style="color:' + (days === 0 ? '#10b981' : 'var(--ink-muted)') + ';">' + dLabel + '</span>' : '')
            + (volCount ? '<span>🙋 ' + volCount + ' volunteer' + (volCount !== 1 ? 's' : '') + '</span>' : '<span style="color:var(--danger);">⚠️ No volunteers assigned</span>')
            + (sngList.length ? '<span>🎵 ' + sngList.length + ' songs</span>' : '')
            + '</div>'
