        + '<div style="font-weight:700;font-size:0.92rem;color:var(--ink);">🙋 Volunteer Slots'
        + (openSlots.length ? ' <span style="display:inline-block;min-width:18px;height:18px;line-height:18px;'
            + 'text-align:center;border-radius:9px;font-size:0.65rem;font-weight:700;background:var(--danger);'
            + 'color:#fff;margin-left:4px;padding:0 4px;">' + openSlots.length + '</span>' : '')
        + '</div>'
        + '<button onclick="Modules.newVolunteer()" style="background:none;border:1px solid var(--line);color:var(--ink);'
        + 'border-radius:6px;padding:4px 10px;font-size:0.74rem;cursor:pointer;font-family:inherit;">+ Assign</button>'
